      });
      const dt2 = Date.now() - t1;
      retrievalMetrics.latency_qdrant_ms = (retrievalMetrics.latency_qdrant_ms || 0) + dt2;
      const c2 = sRes2.statusCode ?? sRes2.status ?? 200;
      if (c2 >= 400) {
        breakerRecordFailure('qdrant');
        retrievalErrors.push({
          service: 'qdrant',
