  return (
    /\bvalidation\b/.test(t) ||
    /guide\s*(de\s*la\s*)?validation/.test(t) ||
    /procedure\s*(de\s*)?validation/.test(t) ||
    /criteres?\s*(de\s*)?validation/.test(t) ||
