}
const sourcesBlock = sourcesLines.length
  ? `

SOURCES :
` + sourcesLines.join(`
`)
  : '';
const promptFinal = prompt + sourcesBlock;

return [
  {
    json: {
      prompt: promptFinal,
      question,
