const root = $input.first().json;
const ctx = $('Code in JavaScript').first()?.json ?? {};
const b3 = $('Code in JavaScript3').first()?.json?.body ?? {};
const webhook = $('Webhook').first()?.json ?? {};

const requestStartMs = webhook._request_start_ms || webhook.body?._request_start_ms || null;
const nowMs = Date.now();

const retrievalMetrics = pickFirstObj(ctx.retrieval_metrics) || {};
const retrievalErrors = Array.isArray(ctx.retrieval_errors) ? ctx.retrieval_errors : [];
const warnings = Array.isArray(root.warnings) ? root.warnings : [];

const requestId = webhook._request_id || webhook.body?._request_id || `req_${nowMs}_${Math.random().toString(36).slice(2, 8)}`;

const latencyTotalMs = typeof requestStartMs === 'number' ? nowMs - requestStartMs : null;

const row = {
  request_id: requestId,
  response_id: root.response_id,
  user_id: root.user_id,
  original_question: root.original_question,
  enriched_query: root.enriched_query,
  query_type: b3.queryType || null,
  language: b3.language || null,
  requirement_detected: null,
  latency_total_ms: latencyTotalMs,
  latency_retrieval_ms: retrievalMetrics.latency_retrieval_ms ?? null,
  latency_ollama_embed_ms: retrievalMetrics.latency_ollama_embed_ms ?? null,
  latency_qdrant_ms: retrievalMetrics.latency_qdrant_ms ?? null,
  retrieval_strategy: retrievalMetrics.retrieval_strategy ?? null,
  chunks_retrieved: ctx.chunks_retrieved ?? null,
  chunks_after_rerank: ctx.chunks_used ?? null,
  qdrant_status: retrievalMetrics.qdrant_status ?? null,
  ollama_status: retrievalMetrics.ollama_status ?? null,
  redis_cache: retrievalMetrics.redis_cache ?? null,
  cache_hit: retrievalMetrics.cache_hit === true ? 1 : retrievalMetrics.cache_hit === false ? 0 : null,
  cache_key_hash: retrievalMetrics.cache_key_hash ?? null,
  llm_status: 'ok',
  response_length: root.response_length ?? (root.response ? String(root.response).length : null),
  warnings_json: warnings.length ? JSON.stringify(warnings) : null,
  retrieval_errors_json: retrievalErrors.length ? JSON.stringify(retrievalErrors) : null,
};

return [{ json: row }];

const response = $input.first().json;
const ctx = $('Code in JavaScript').first()?.json ?? {};
const retrievalErrors = Array.isArray(ctx.retrieval_errors) ? ctx.retrieval_errors : [];

if (!retrievalErrors.length) return [];

const base = {
  created_at: response.created_at,
  response_id: response.response_id,
  user_id: response.user_id,
  original_question: response.original_question,
  enriched_query: response.enriched_query,
};

return retrievalErrors.map((e) => ({
  json: {
    created_at: base.created_at,
    response_id: base.response_id,
    user_id: base.user_id,
    service: e.service || 'unknown',
    operation: e.operation || '',
    error_message: e.message || '',
    stack: e.stack || null,
    http_status: e.http_status || e.statusCode || null,
    original_question: base.original_question,
    enriched_query: base.enriched_query,
  },
}));
